
"use client";

import { useState, useEffect, useMemo } from 'react';
import { PageHeader } from '@/components/page-header';
import type { Order, UserProfile, Vendor } from '@/types';
import { useFirebase } from '@/firebase';
import { Loader2, Lock, Wifi, WifiOff, Users as UsersIcon, DollarSign, ShoppingBag, Activity } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { formatDistanceToNow, fromUnixTime, eachDayOfInterval, format, startOfTomorrow } from 'date-fns';
import { useAppContext } from '@/components/layout/app-content-wrapper';
import { cn } from '@/lib/utils';
import { Skeleton } from '@/components/ui/skeleton';
import { UserAnalyticsDetail } from '@/components/analytics/user-analytics-detail';
import { getAllUsers } from '@/app/auth/actions';
import { getOrdersFromWooCommerce } from '@/app/orders/actions';
import { useToast } from '@/hooks/use-toast';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Button } from '@/components/ui/button';
import { Calendar as CalendarIcon } from 'lucide-react';
import { Calendar } from "@/components/ui/calendar";
import type { DateRange } from "react-day-picker";

interface UserPresence {
  state: 'online' | 'offline';
  last_seen: number; 
  time_spent: number; 
}

export interface EnrichedUser extends UserProfile {
  presence?: UserPresence;
}

const gradientStyles = [
  "bg-gradient-to-br from-purple-500 to-pink-500",
  "bg-gradient-to-br from-blue-500 to-cyan-400",
  "bg-gradient-to-br from-orange-400 to-red-500",
  "bg-gradient-to-br from-green-400 to-lime-500",
];

const COLORS = ['hsl(var(--chart-1))', 'hsl(var(--chart-2))', 'hsl(var(--chart-3))', 'hsl(var(--chart-4))', 'hsl(var(--chart-5))'];

const formatTimeSpent = (seconds: number): string => {
  if (seconds < 60) return `${Math.floor(seconds)}s`;
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ${minutes % 60}m`;
  const days = Math.floor(hours / 24);
  return `${days}d ${hours % 24}h`;
};


const StatsCard = ({ title, value, icon, className }: { title: string; value: string; icon: React.ReactNode; className?: string }) => (
    <Card className={cn("shadow-lg hover:shadow-xl transition-shadow duration-300 text-white", className)}>
      <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
        <CardTitle className="text-sm font-medium text-white/80">{title}</CardTitle>
        {icon}
      </CardHeader>
      <CardContent>
        <div className="text-2xl font-bold text-white">{value}</div>
      </CardContent>
    </Card>
);


export default function AnalyticsPage() {
  const { rtdb } = useFirebase();
  const { userProfile, authLoading } = useAppContext();
  const { toast } = useToast();

  const [users, setUsers] = useState<EnrichedUser[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [dataLoading, setDataLoading] = useState(true);
  const [selectedUser, setSelectedUser] = useState<EnrichedUser | null>(null);

  const [dateRange, setDateRange] = useState<DateRange | undefined>(() => {
    const today = new Date();
    const sixDaysAgo = new Date();
    sixDaysAgo.setDate(today.getDate() - 6);
    return { from: sixDaysAgo, to: today };
  });

  const isSuperAdmin = userProfile?.role === 'super-admin';
  const isLoading = dataLoading || authLoading;

  useEffect(() => {
    if (authLoading || !isSuperAdmin) {
        if (!authLoading) setDataLoading(false);
        return;
    }
    
    let isMounted = true;
    
    const fetchAndListen = async () => {
        if (!isMounted) return;
        setDataLoading(true);

        const [usersResult, ordersResult] = await Promise.all([
            getAllUsers(),
            getOrdersFromWooCommerce()
        ]);
        
        if (!isMounted) return;

        if (usersResult.success && usersResult.data) {
            setUsers(usersResult.data);
        } else {
            console.error("Failed to fetch users from Firestore.");
            toast({ variant: 'destructive', title: 'Failed to load users' });
        }

        if (ordersResult.success && ordersResult.data) {
            setOrders(ordersResult.data);
        } else {
            console.error("Failed to fetch orders from WooCommerce.");
            toast({ variant: 'destructive', title: 'Failed to load orders' });
        }
      
        setDataLoading(false);

        if (rtdb) {
            const statusRef = ref(rtdb, 'status');
            const unsubscribe = onValue(statusRef, (snapshot) => {
                if (!isMounted) return;
                const presenceData = snapshot.val() as Record<string, UserPresence> | null;
                if (presenceData) {
                    setUsers(currentUsers => 
                        currentUsers.map(user => {
                            const userPresence = presenceData[user.uid];
                            return userPresence ? { ...user, presence: userPresence } : user;
                        })
                    );
                }
            }, (error) => {
                console.error("Error listening to presence data:", error);
            });
            return () => unsubscribe();
        }
    };

    fetchAndListen();

    return () => {
        isMounted = false;
    };
    
  }, [rtdb, isSuperAdmin, authLoading, toast]);
  
  const { onlineCount, totalSales, totalOrders, newCustomers, weeklyOrderData, sortedUsers } = useMemo(() => {
    const online = users.filter(u => u.presence?.state === 'online').length;
    
    const fromDate = dateRange?.from ? new Date(dateRange.from) : new Date(0);
    const toDate = dateRange?.to ? new Date(dateRange.to) : new Date();
    fromDate.setHours(0,0,0,0);
    toDate.setHours(23,59,59,999);

    const filteredOrders = orders.filter(order => {
        const orderDate = new Date(order.timestamp);
        return orderDate >= fromDate && orderDate <= toDate;
    });

    const sales = filteredOrders.reduce((sum, order) => sum + order.totalAmount, 0);
    const orderCount = filteredOrders.length;
    const customerEmails = new Set(filteredOrders.map(o => o.gmail));

    const intervalDays = eachDayOfInterval({ start: fromDate, end: toDate });
    const orderCountsByDay = intervalDays.map(day => ({
      name: format(day, 'MMM d'),
      date: format(day, 'yyyy-MM-dd'),
      orders: 0
    }));

    filteredOrders.forEach(order => {
        const orderDateStr = format(new Date(order.timestamp), 'yyyy-MM-dd');
        const dayData = orderCountsByDay.find(d => d.date === orderDateStr);
        if (dayData) {
            dayData.orders += 1;
        }
    });

    const sUsers = [...users].sort((a, b) => {
        const aOnline = a.presence?.state === 'online';
        const bOnline = b.presence?.state === 'online';
        if (aOnline && !bOnline) return -1;
        if (!aOnline && bOnline) return 1;
        return (b.presence?.last_seen || 0) - (a.presence?.last_seen || 0);
    });

    return { 
        onlineCount: online, 
        totalSales: sales,
        totalOrders: orderCount,
        newCustomers: customerEmails.size,
        weeklyOrderData: orderCountsByDay,
        sortedUsers: sUsers,
    };
  }, [users, orders, dateRange]);
  
  if (authLoading) {
    return (
         <div className="flex flex-col h-full">
            <PageHeader
                title="Platform Analytics"
                description="Comprehensive overview of user activity, sales, and system performance."
            />
            <div className="flex-1 flex justify-center items-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        </div>
    );
  }

  if (!isSuperAdmin) {
    return (
      <div className="flex flex-col h-full">
        <PageHeader
          title="Platform Analytics"
          description="Comprehensive overview of user activity, sales, and system performance."
        />
        <div className="flex-1 flex flex-col justify-center items-center text-center p-4">
            <Lock className="h-16 w-16 text-destructive mb-4" />
            <h2 className="text-2xl font-bold text-destructive">Access Denied</h2>
            <p className="text-muted-foreground mt-2">Only Super Admins can access this page.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      <PageHeader
        title="Platform Analytics"
        description="Comprehensive overview of user activity, sales, and system performance."
      />
      <div className="flex-1 p-4 md:p-6 overflow-auto">
        {isLoading ? (
          <div className="space-y-6">
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
                <Skeleton className="h-28" />
                <Skeleton className="h-28" />
                <Skeleton className="h-28" />
                <Skeleton className="h-28" />
            </div>
            <Skeleton className="h-80 w-full" />
            <Skeleton className="h-6 w-48" />
            <div className="space-y-4">
                {Array.from({ length: 4 }).map((_, index) => (
                    <Skeleton key={index} className="h-20 w-full" />
                ))}
            </div>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
                <StatsCard title="Total Sales" value={`₹${totalSales.toLocaleString('en-IN')}`} icon={<DollarSign className="text-white/70 h-5 w-5" />} className={gradientStyles[0]} />
                <StatsCard title="Total Orders" value={totalOrders.toString()} icon={<ShoppingBag className="text-white/70 h-5 w-5" />} className={gradientStyles[1]} />
                <StatsCard title="New Customers" value={newCustomers.toString()} icon={<UsersIcon className="text-white/70 h-5 w-5" />} className={gradientStyles[2]} />
                <StatsCard title="Online Users" value={onlineCount.toString()} icon={<Wifi className="text-white/70 h-5 w-5" />} className={gradientStyles[3]} />
            </div>

            <Card className="shadow-lg">
               <CardHeader className="flex-row items-center justify-between">
                  <div >
                      <CardTitle className="font-headline text-xl">Order Activity</CardTitle>
                      <CardContent className="text-xs text-muted-foreground p-0 pt-1">Sales trends over the selected period.</CardContent>
                  </div>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button
                        id="date"
                        variant={"outline"}
                        size="sm"
                        className={cn(
                          "w-[240px] justify-start text-left font-normal h-9 text-sm",
                          !dateRange && "text-muted-foreground"
                        )}
                      >
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {dateRange?.from ? (
                          dateRange.to ? (
                            <>
                              {format(dateRange.from, "LLL dd, y")} -{" "}
                              {format(dateRange.to, "LLL dd, y")}
                            </>
                          ) : (
                            format(dateRange.from, "LLL dd, y")
                          )
                        ) : (
                          <span>Pick a date</span>
                        )}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0" align="end">
                      <Calendar
                        initialFocus
                        mode="range"
                        defaultMonth={dateRange?.from}
                        selected={dateRange}
                        onSelect={setDateRange}
                        numberOfMonths={2}
                      />
                    </PopoverContent>
                  </Popover>
              </CardHeader>
              <CardContent className="pt-4">
                <ResponsiveContainer width="100%" height={250}>
                  <BarChart data={weeklyOrderData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border)/0.5)" vertical={false} />
                    <XAxis dataKey="name" stroke="hsl(var(--muted-foreground))" fontSize={12} axisLine={false} tickLine={false} />
                    <YAxis stroke="hsl(var(--muted-foreground))" fontSize={12} axisLine={false} tickLine={false} allowDecimals={false} />
                    <Tooltip
                      contentStyle={{ backgroundColor: 'hsl(var(--background))', border: '1px solid hsl(var(--border))', borderRadius: 'var(--radius)' }}
                      labelStyle={{ color: 'hsl(var(--foreground))', fontWeight: 'bold' }}
                      itemStyle={{ color: 'hsl(var(--foreground))' }}
                      cursor={{fill: 'hsl(var(--muted)/0.3)'}}
                    />
                    <Bar dataKey="orders" name="Orders" radius={[4, 4, 0, 0]}>
                       {weeklyOrderData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            <div>
                <h2 className="text-xl font-semibold tracking-tight mb-4">User Presence ({sortedUsers.length})</h2>
                <div className="space-y-2">
                   {sortedUsers.map((user) => (
                      <Card 
                        key={user.uid} 
                        className="shadow-md hover:shadow-lg hover:border-primary/50 transition-all duration-300 cursor-pointer"
                        onClick={() => setSelectedUser(user)}
                      >
                        <div className="flex items-center gap-4 p-3">
                          <div className="relative shrink-0">
                             <Avatar className="h-10 w-10 border-2 border-primary/50">
                                <AvatarImage src={user.photoURL} alt={user.displayName} data-ai-hint="user avatar" />
                                <AvatarFallback>{user.displayName?.[0] || 'U'}</AvatarFallback>
                            </Avatar>
                             <span className={cn(
                                "absolute bottom-0 right-0 block h-3 w-3 rounded-full border-2 border-background",
                                user.presence?.state === 'online' ? 'bg-green-500' : 'bg-gray-400'
                             )}/>
                          </div>
                          
                          <div className="flex-grow">
                             <p className="font-semibold text-sm">{user.displayName}</p>
                             <p className="text-xs text-muted-foreground">{user.email}</p>
                          </div>

                          <div className="text-right shrink-0 space-y-1 w-40">
                             <p className="text-xs text-muted-foreground">
                                {user.presence?.state === 'online'
                                ? <span className="text-green-500 font-bold flex items-center justify-end gap-1.5"><Wifi className="h-3 w-3" />Online</span>
                                : user.presence?.last_seen
                                ? `${formatDistanceToNow(fromUnixTime(user.presence.last_seen / 1000), { addSuffix: true })}`
                                : 'Never'}
                            </p>
                            <p className="text-xs font-semibold text-foreground flex items-center justify-end gap-1.5">
                                <Activity className="h-3 w-3 text-muted-foreground" />
                                {user.presence?.time_spent ? formatTimeSpent(user.presence.time_spent) : 'N/A'}
                            </p>
                          </div>
                        </div>
                      </Card>
                    ))}
                </div>
            </div>
             {users.length === 0 && !dataLoading && (
                <div className="col-span-full text-center py-12">
                    <p className="font-body text-muted-foreground">No user activity data to display yet.</p>
                </div>
             )}
          </div>
        )}
      </div>
      <UserAnalyticsDetail 
        user={selectedUser} 
        isOpen={!!selectedUser} 
        onOpenChange={(open) => { if(!open) setSelectedUser(null); }}
        formatTimeSpent={formatTimeSpent}
      />
    </div>
  );
}

    